/**
 * generator.ts — Produces agent config files from ProjectDNA.
 *
 * Self-contained generators that mirror the Studio scaffolder templates
 * but are bundled into this CLI package with zero external dependencies.
 *
 * Generated file map:
 *   AGENTS.md                         → project root (universal)
 *   .cursorrules                      → project root (Cursor)
 *   .github/copilot-instructions.md   → project root (Copilot)
 *   GEMINI.md                         → project root (Gemini)
 *   .claude/CLAUDE.md                 → Claude Code
 *   .claude/NORTH_STAR.md             → Decision oracle
 *   .claude/MEMORY.md                 → Persistent memory
 *   team-connect.mjs                  → Multi-IDE coordination
 */

import type { ProjectDNA } from './scanner.js';

export interface GeneratedFile {
  /** Relative path from project root */
  path: string;
  /** File content */
  content: string;
  /** Human-readable description */
  description: string;
}

// ─── Shared helpers ────────────────────────────────────────────────────────

function testCmd(dna: ProjectDNA): string {
  if (dna.techStack.includes('vitest')) return dna.techStack.includes('pnpm') ? 'pnpm vitest' : 'npx vitest';
  if (dna.techStack.includes('jest')) return dna.techStack.includes('pnpm') ? 'pnpm jest' : 'npx jest';
  if (dna.languages.includes('py')) return 'pytest';
  if (dna.languages.includes('go')) return 'go test ./...';
  if (dna.languages.includes('rs')) return 'cargo test';
  return dna.techStack.includes('pnpm') ? 'pnpm test' : 'npm test';
}

function buildCmd(dna: ProjectDNA): string {
  if (dna.techStack.includes('pnpm')) return 'pnpm build';
  if (dna.techStack.includes('yarn')) return 'yarn build';
  if (dna.languages.includes('go')) return 'go build ./...';
  if (dna.languages.includes('rs')) return 'cargo build';
  if (dna.languages.includes('py')) return 'python -m build';
  return 'npm run build';
}

function lintCmd(dna: ProjectDNA): string {
  if (dna.techStack.includes('eslint')) return dna.techStack.includes('pnpm') ? 'pnpm lint' : 'npx eslint .';
  if (dna.languages.includes('py')) return 'ruff check .';
  if (dna.languages.includes('go')) return 'golangci-lint run';
  if (dna.languages.includes('rs')) return 'cargo clippy';
  return dna.techStack.includes('pnpm') ? 'pnpm lint' : 'npm run lint';
}

function stackConventions(dna: ProjectDNA): string {
  const rules: string[] = [];
  if (dna.techStack.includes('typescript')) {
    rules.push('- TypeScript strict mode. No `any` — use `unknown`.');
    rules.push('- Explicit return types on exported functions.');
    rules.push('- `.tsx` for JSX files.');
  }
  if (dna.languages.includes('py')) {
    rules.push('- Type hints on all public functions.');
    rules.push('- Format: black. Lint: ruff.');
  }
  if (dna.languages.includes('go')) {
    rules.push('- Always check errors. No `_` discards.');
    rules.push('- `context.Context` as first I/O parameter.');
  }
  if (dna.languages.includes('rs')) {
    rules.push('- No `unwrap()` in production — use `?` or explicit error handling.');
  }
  if (dna.frameworks.includes('next.js')) {
    rules.push('- Server Components by default. `\'use client\'` only when needed.');
  }
  if (dna.frameworks.includes('react') && !dna.frameworks.includes('next.js')) {
    rules.push('- Functional components only. Co-locate tests.');
  }
  rules.push('- Never commit secrets. Use `.env`.');
  rules.push('- `git add <file>` only. Never `git add -A`.');
  return rules.join('\n');
}

// ─── AGENTS.md ─────────────────────────────────────────────────────────────

function generateAgentsMd(dna: ProjectDNA): string {
  const isMonorepo = dna.packageCount > 1;
  return `# AGENTS.md — ${dna.name}

> Universal agent instructions. Read by Codex, Copilot, Cursor, Windsurf, Amp, Devin, Continue.
> Generated by [HoloScript](https://holoscript.net) — upgrade at [studio.holoscript.net](https://studio.holoscript.net)

## Project

- **Languages**: ${dna.languages.join(', ') || 'not detected'}
- **Frameworks**: ${dna.frameworks.join(', ') || 'none'}
- **Structure**: ${isMonorepo ? `Monorepo (${dna.packageCount} packages)` : 'Single package'}

## Commands

| Action | Command |
|--------|---------|
| Build | \`${buildCmd(dna)}\` |
| Test | \`${testCmd(dna)}\` |
| Lint | \`${lintCmd(dna)}\` |

## Conventions

${stackConventions(dna)}

## Workflow

1. **Read** before editing — never modify blind
2. **Test** after changes — \`${testCmd(dna)}\`
3. **Commit** with explicit staging — \`git add <file>\`
4. **Lint** before committing — \`${lintCmd(dna)}\`

## Decision Defaults

- New file or existing? **Existing** first
- Ask user or decide? **Decide**, then explain
- Test failing? **Fix** if yours, **note** if pre-existing
- New dependency? **Use existing first**, ask before adding runtime deps

## Skills Reference (Read Before Working)

Skills are concentrated knowledge files for each domain. **Read the relevant skill before working.**

| Domain | Skill File | What It Knows |
|--------|-----------|---------------|
| Project work | \`.claude/skills/dev/SKILL.md\` | Build, test, ship workflow |
| Code scanning | \`.claude/skills/scan/SKILL.md\` | Markers, health, coverage |
| Documentation | \`.claude/skills/documenter/SKILL.md\` | Voice, staleness, versions |
| Code review | \`.claude/skills/review/SKILL.md\` | Conventions, security, perf |

**Claude Code**: Invoke via Skill tool (\`/dev\`, \`/scan\`). Skills fork context — saves your main window.
**All other agents**: Read directly — \`cat .claude/skills/<name>/SKILL.md\`.

## Additional Features

- Decision Oracle: \`.claude/NORTH_STAR.md\`
- Persistent Memory: \`.claude/MEMORY.md\`
- Team Coordination: \`team-connect.mjs\`
- Upgrade: \`npx @holoscript/agent-setup --upgrade\` or [studio.holoscript.net](https://studio.holoscript.net)
`;
}

