// ─── team-connect.mjs ──────────────────────────────────────────────────────

function generateTeamConnect(): string {
  return `#!/usr/bin/env node
/**
 * team-connect.mjs — Multi-IDE agent coordination bridge.
 *
 * Connects any AI agent (Claude, Copilot, Gemini, Cursor, Codex, Devin)
 * to a shared team board for coordination across IDEs.
 *
 * Usage:
 *   node team-connect.mjs --once --name=copilot --ide=vscode
 *   node team-connect.mjs --daemon --name=gemini --ide=antigravity
 *   node team-connect.mjs --report --name=agent --ide=ide-type
 *   node team-connect.mjs --board
 *
 * Requires HOLOMESH_API_KEY and HOLOMESH_TEAM_ID in .env
 *
 * For full team features, upgrade at: https://studio.holoscript.net
 */

import fs from 'node:fs';
import path from 'node:path';

// ─── Config ────────────────────────────────────────────────────────────────

const ENV_PATHS = [
  path.join(process.cwd(), '.env'),
  path.join(process.env.HOME || process.env.USERPROFILE || '', '.ai-ecosystem', '.env'),
];

function loadEnv() {
  for (const envPath of ENV_PATHS) {
    if (fs.existsSync(envPath)) {
      const content = fs.readFileSync(envPath, 'utf-8');
      for (const line of content.split('\\n')) {
        const match = line.match(/^([A-Z_]+)=(.*)$/);
        if (match && !process.env[match[1]]) {
          process.env[match[1]] = match[2].replace(/^["']|["']$/g, '');
        }
      }
      break;
    }
  }
}

loadEnv();

const API_BASE = process.env.HOLOMESH_API_URL || 'https://mcp.holoscript.net/api/holomesh';
const API_KEY = process.env.HOLOMESH_API_KEY || '';
const TEAM_ID = process.env.HOLOMESH_TEAM_ID || '';

// ─── Args ──────────────────────────────────────────────────────────────────

const args = process.argv.slice(2);
const flags = Object.fromEntries(
  args.filter(a => a.startsWith('--')).map(a => {
    const [k, v] = a.slice(2).split('=');
    return [k, v || true];
  })
);

const agentName = flags.name || 'agent';
const ideType = flags.ide || 'unknown';
const mode = flags.once ? 'once' : flags.daemon ? 'daemon' : flags.report ? 'report' : flags.board ? 'board' : 'once';

// ─── API helpers ───────────────────────────────────────────────────────────

async function api(method, endpoint, body) {
  if (!API_KEY || !TEAM_ID) {
    console.log('[team-connect] Missing HOLOMESH_API_KEY or HOLOMESH_TEAM_ID in .env');
    console.log('[team-connect] Get credentials at: https://studio.holoscript.net/start');
    return null;
  }
  try {
    const res = await fetch(\`\${API_BASE}/team/\${TEAM_ID}\${endpoint}\`, {
      method,
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': API_KEY,
      },
      body: body ? JSON.stringify(body) : undefined,
    });
    if (!res.ok) return null;
    return res.json();
  } catch {
    return null;
  }
}

// ─── Commands ──────────────────────────────────────────────────────────────

async function heartbeat() {
  return api('POST', '/presence', { agent: agentName, ide: ideType, status: 'active' });
}

async function readBoard() {
  const board = await api('GET', '/board');
  if (!board) return null;
  console.log('\\n=== TEAM BOARD ===');
  const tasks = board.tasks || board.items || [];
  const open = tasks.filter(t => t.status === 'open');
  const claimed = tasks.filter(t => t.status === 'claimed' || t.status === 'in-progress');
  const done = tasks.filter(t => t.status === 'done');
  console.log(\`Open: \${open.length} | Claimed: \${claimed.length} | Done: \${done.length}\`);
  for (const t of open.slice(0, 5)) {
    console.log(\`  [\${t.priority || '-'}] \${t.title}\`);
  }
  return board;
}

async function readMessages() {
  const msgs = await api('GET', '/messages');
  if (!msgs || !msgs.length) return;
  console.log('\\n=== INBOX ===');
  for (const m of msgs.slice(0, 5)) {
    console.log(\`  [\${m.from}] \${m.text || m.content || ''}\`);
  }
}

async function run() {
  if (mode === 'board') {
    await readBoard();
    return;
  }

  // Heartbeat
  await heartbeat();
  console.log(\`[team-connect] \${agentName}@\${ideType} connected\`);

  // Read board + messages
  await readBoard();
  await readMessages();

  if (mode === 'daemon') {
    // Heartbeat loop
    setInterval(() => heartbeat(), 60_000);
    setInterval(async () => {
      await readBoard();
      await readMessages();
    }, 300_000);
    console.log('[team-connect] Daemon mode — heartbeat every 60s, refresh every 5m');
  }

  if (mode === 'report') {
    // Post session summary
    await api('POST', '/messages', {
      from: agentName,
      type: 'handoff',
      text: \`Session end from \${agentName}@\${ideType}. Check git log for details.\`,
    });
    console.log('[team-connect] Session report posted');
  }
}

run().catch(err => {
  console.error('[team-connect] Error:', err.message);
  process.exit(1);
});
`;
}

// ─── Public API ────────────────────────────────────────────────────────────

export function generateAllFiles(dna: ProjectDNA): GeneratedFile[] {
  return [
    {
      path: 'AGENTS.md',
      content: generateAgentsMd(dna),
      description: 'Universal agent instructions (Codex, Copilot, Cursor, Windsurf, Amp, Devin)',
    },
    {
      path: '.cursorrules',
      content: generateCursorRules(dna),
      description: 'Cursor IDE agent instructions',
    },
    {
      path: '.github/copilot-instructions.md',
      content: generateCopilotInstructions(dna),
      description: 'GitHub Copilot instructions',
    },
    {
      path: 'GEMINI.md',
      content: generateGeminiMd(dna),
      description: 'Gemini CLI / Code Assist instructions',
    },
    {
      path: '.claude/CLAUDE.md',
      content: generateClaudeMd(dna),
      description: 'Claude Code project instructions',
    },
    {
      path: '.claude/NORTH_STAR.md',
      content: generateNorthStar(dna),
      description: 'Decision oracle — prevents agent stalls',
    },
    {
      path: '.claude/MEMORY.md',
      content: generateMemory(dna),
      description: 'Persistent cross-session memory',
    },
    {
      path: 'team-connect.mjs',
      content: generateTeamConnect(),
      description: 'Multi-IDE agent coordination bridge',
    },
  ];
}
